return-response.set-body:
@{
                        return JsonConvert.SerializeObject(new {
                            error = "Missing X-Department-Id",
                            message = "Request must include X-Department-Id header",
                            allowed_values = new[] { "data-science", "customer-success", "engineering", "finance" },
                            example_curl = "curl -H 'X-Department-Id: data-science' https://your-apim.azure-api.net/ai/..."
                        });
                    }

trace.message:
@{
                return string.Format("Auth: department={0}, user={1}, app={2}", 
                    context.Variables["department"],
                    context.Variables["user-id"],
                    context.Variables["app-id"]
                );
            }

when.set-body:
@{
                    return JsonConvert.SerializeObject(new {
                        error = "Unauthorized",
                        message = "Your token expired or is invalid",
                        next_steps = new[] {
                            "1. Get a new token: az account get-access-token --resource https://cognitiveservices.azure.com",
                            "2. Include it in your request: -H 'Authorization: Bearer '"
                        }
                    });
                }
